"use strict";(self.webpackChunkPradocument=self.webpackChunkPradocument||[]).push([[2640],{3388:(n,s,a)=>{a.r(s),a.d(s,{data:()=>e});const e={key:"v-3459d284",path:"/module/puppeteer/%E5%B8%B8%E7%94%A8puppeteer%E7%88%AC%E8%99%ABapi.html",title:"",lang:"en-US",frontmatter:{},excerpt:"",headers:[{level:2,title:"一、安装和使用",slug:"一、安装和使用",children:[{level:3,title:"1.1安装",slug:"_1-1安装",children:[]},{level:3,title:"1.2 使用",slug:"_1-2-使用",children:[]}]},{level:2,title:"二、基本用法",slug:"二、基本用法",children:[{level:3,title:"2.1 调整页面",slug:"_2-1-调整页面",children:[]},{level:3,title:"2.2 模拟输入和点击",slug:"_2-2-模拟输入和点击",children:[]},{level:3,title:"2.3 iframe处理",slug:"_2-3-iframe处理",children:[]},{level:3,title:"2.4 waitFor函数",slug:"_2-4-waitfor函数",children:[]},{level:3,title:"2.5 selector和emulate",slug:"_2-5-selector和emulate",children:[]},{level:3,title:"2.6 监听事件",slug:"_2-6-监听事件",children:[]}]},{level:2,title:"三、伪装移动端",slug:"三、伪装移动端",children:[]}],filePathRelative:"module/puppeteer/常用puppeteer爬虫api.md",git:{updatedTime:1657620056e3,contributors:[{name:"孤城致幻",email:"Xast@123456",commits:1}]}}},7727:(n,s,a)=>{a.r(s),a.d(s,{default:()=>u});var e=a(6252);const p=(0,e.uE)('<h2 id="一、安装和使用" tabindex="-1"><a class="header-anchor" href="#一、安装和使用" aria-hidden="true">#</a> 一、安装和使用</h2><h3 id="_1-1安装" tabindex="-1"><a class="header-anchor" href="#_1-1安装" aria-hidden="true">#</a> 1.1安装</h3><p><code>cnpm i -S puppeteer</code> 用cnpm安装没有试过报错，默认会下载puppeteer配套版本的Chromium。</p><h3 id="_1-2-使用" tabindex="-1"><a class="header-anchor" href="#_1-2-使用" aria-hidden="true">#</a> 1.2 使用</h3><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code><span class="token keyword">const</span> puppeteer <span class="token operator">=</span> <span class="token function">require</span><span class="token punctuation">(</span><span class="token string">&#39;puppeteer&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\n\n<span class="token punctuation">(</span><span class="token keyword">async</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span>\n   <span class="token keyword">const</span> browser <span class="token operator">=</span> <span class="token keyword">await</span> puppeteer<span class="token punctuation">.</span><span class="token function">launch</span><span class="token punctuation">(</span><span class="token punctuation">{</span>\n    <span class="token literal-property property">headless</span><span class="token operator">:</span> <span class="token boolean">false</span><span class="token punctuation">,</span> <span class="token comment">//默认为true（无头），不显示浏览器界面</span>\n    <span class="token literal-property property">slowMo</span> <span class="token operator">:</span><span class="token number">200</span><span class="token punctuation">,</span> <span class="token comment">//减速显示，有时会作为模拟人操作特意减速</span>\n    <span class="token literal-property property">devtools</span><span class="token operator">:</span> <span class="token boolean">true</span> <span class="token comment">//显示开发者工具。页面宽高默认800*600,把开发者工具显示再隐藏页面会占满屏幕，有没有大佬解释下？</span>\n  <span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\n  <span class="token comment">//生成Page对象</span>\n  <span class="token comment">//const page = await browser.newPage();//官网写法：一打开浏览器会打开两个tab，第二个才是你正在操作的tab</span>\n  <span class="token keyword">const</span> page <span class="token operator">=</span> <span class="token punctuation">(</span><span class="token keyword">await</span> browser<span class="token punctuation">.</span><span class="token function">pages</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">[</span><span class="token number">0</span><span class="token punctuation">]</span><span class="token punctuation">;</span> <span class="token comment">//这是我的写法，只有一个tab</span>\n  <span class="token keyword">await</span> page<span class="token punctuation">.</span><span class="token function">goto</span><span class="token punctuation">(</span><span class="token string">&#39;https://www.juejin.com&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">//跳转到掘金</span>\n <span class="token comment">//请开始你的表演...</span>\n\n  <span class="token keyword">await</span> browser<span class="token punctuation">.</span><span class="token function">close</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">//关闭浏览器</span>\n<span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br></div></div><p>puppeteer基本上每个操作都会返回一个Promise,记得要用await接收下一步的操作。</p>',6),t={href:"https://link.juejin.cn/?target=https%3A%2F%2Fgithub.com%2FGoogleChrome%2Fpuppeteer%2Ftree%2Fmaster%2Fexamples",title:"https://github.com/GoogleChrome/puppeteer/tree/master/examples",target:"_blank",rel:"noopener noreferrer"},o=(0,e.Uk)("puppeteer上也提供了一些第三方写的爬虫demo"),c=(0,e.Uk)("，不过感觉封装得有点多，先不玩。"),l=(0,e.uE)('<h2 id="二、基本用法" tabindex="-1"><a class="header-anchor" href="#二、基本用法" aria-hidden="true">#</a> 二、基本用法</h2><h3 id="_2-1-调整页面" tabindex="-1"><a class="header-anchor" href="#_2-1-调整页面" aria-hidden="true">#</a> 2.1 调整页面</h3><p>页面宽高默认800*600,我觉得太小。我一般都会先初始化页面大小。</p><p>和上面说的一样，这只是初始化的时候的大小，当打开再隐藏开发者工具后，页面就会占满全屏了，不知道这是不是bug。</p><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code><span class="token keyword">await</span> page<span class="token punctuation">.</span><span class="token function">setViewport</span><span class="token punctuation">(</span><span class="token punctuation">{</span>\n    <span class="token literal-property property">width</span><span class="token operator">:</span> <span class="token number">1280</span><span class="token punctuation">,</span>\n    <span class="token literal-property property">height</span><span class="token operator">:</span> <span class="token number">800</span>\n  <span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><h3 id="_2-2-模拟输入和点击" tabindex="-1"><a class="header-anchor" href="#_2-2-模拟输入和点击" aria-hidden="true">#</a> 2.2 模拟输入和点击</h3><p>目测底层是用document.querySelector()</p><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code><span class="token keyword">await</span> page<span class="token punctuation">.</span><span class="token function">type</span><span class="token punctuation">(</span>selector<span class="token punctuation">,</span> <span class="token string">&#39;Hello puppeteer&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">//找到对应的选择器然后填充值。如果之前设置了slowMo会看到像人打字一样，值是一个一个填进&lt;input/&gt;</span>\n<span class="token keyword">await</span> page<span class="token punctuation">.</span><span class="token function">click</span><span class="token punctuation">(</span>selector<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">//模拟点击，这对传统异步分页（url没有分页参数）很有用，selector定在下一页的标签上</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h3 id="_2-3-iframe处理" tabindex="-1"><a class="header-anchor" href="#_2-3-iframe处理" aria-hidden="true">#</a> 2.3 iframe处理</h3><p>如果网页内有用iframe等标签，这时page对象是无法读取<code>&lt;iframe&gt;</code>里面的内容的，需要用到<code>page.frames()</code>。返回一个Frame对象数组。 通常iframe会有name属性，判断name属性可以快速获取单个Frame对象的内容。</p><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code><span class="token keyword">let</span> iframe <span class="token operator">=</span> <span class="token keyword">await</span> page<span class="token punctuation">.</span><span class="token function">frames</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\niframe<span class="token punctuation">.</span><span class="token function">find</span><span class="token punctuation">(</span><span class="token parameter">f</span> <span class="token operator">=&gt;</span> f<span class="token punctuation">.</span><span class="token function">name</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">===</span> <span class="token string">&#39;name&#39;</span><span class="token punctuation">)</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h3 id="_2-4-waitfor函数" tabindex="-1"><a class="header-anchor" href="#_2-4-waitfor函数" aria-hidden="true">#</a> 2.4 waitFor函数</h3><p>waitFor函数是简写，Page和Frame对象都有。我只会用以下两种方式，剩下了请大佬指点一下。</p><blockquote><p>为了简化，Page和Frame对象都有的api，我不会再特意说明，会在代码中直接体现。</p></blockquote><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code><span class="token keyword">await</span> iframe<span class="token punctuation">.</span>waitFor（<span class="token string">&#39;.contain .item&#39;</span>） <span class="token comment">//在&lt;iframe&gt;中等待&#39;.contain .item&#39;的节点出现，阻塞结束（ps:优先使用，有时200ms我是等不起的）</span>\n<span class="token keyword">await</span> page<span class="token punctuation">.</span>waitFor（<span class="token number">200</span>）<span class="token comment">//页面等待200ms</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h3 id="_2-5-selector和emulate" tabindex="-1"><a class="header-anchor" href="#_2-5-selector和emulate" aria-hidden="true">#</a> 2.5 selector和emulate</h3><p>为什么要合在一点写呢？因为确实有一个组合的api叫<code>eval</code></p><p>先分开说说吧。</p><h4 id="_2-5-1-selector" tabindex="-1"><a class="header-anchor" href="#_2-5-1-selector" aria-hidden="true">#</a> 2.5.1 selector</h4><p>目测底层是用document.querySelector()和document.querySelectorAll()。熟悉这两个api的人应该很容易上手。</p><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code><span class="token comment">//ps:较少用</span>\npage<span class="token punctuation">.</span><span class="token function">$</span><span class="token punctuation">(</span>selector<span class="token punctuation">)</span> <span class="token comment">// document.querySelector()</span>\niframe<span class="token punctuation">.</span><span class="token operator">?</span><span class="token punctuation">(</span>selector<span class="token punctuation">)</span> <span class="token comment">// document.querySelectorAll()， ?是All的意思</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><h4 id="_2-5-2-emulate" tabindex="-1"><a class="header-anchor" href="#_2-5-2-emulate" aria-hidden="true">#</a> 2.5.2 emulate</h4><p>这里首先要有个概念，puppeteer爬虫解析dom在浏览器，这个api的实参在浏览器中。所以可以在这个函数内进行dom操作，同时本地的node api是无法在这里运行的，运行<code>console.log(global)</code>会报错。</p><p>举个栗子：在函数内有<code>console.log(&#39;按f12,我出现在浏览器的console中，并不在node命令行&#39;)</code></p><p>你会发现node命令行看不到这句话，而在Chromium的console中看见。因此你应该理解他的运行环境是当前网站，而不是你本地的node。</p><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code><span class="token comment">//ps:更少用</span>\n<span class="token keyword">await</span> page<span class="token punctuation">.</span><span class="token function">evaluate</span><span class="token punctuation">(</span><span class="token parameter">el</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span>\n    <span class="token comment">//喜闻乐见的dom操作</span>\n<span class="token punctuation">}</span><span class="token punctuation">)</span>\n<span class="token keyword">await</span> iframe<span class="token punctuation">.</span><span class="token function">evaluate</span><span class="token punctuation">(</span><span class="token parameter">el</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span>\n    <span class="token comment">//请开始你的表演</span>\n    console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token string">&#39;按f12,我出现在浏览器的console中，并不在node命令行&#39;</span><span class="token punctuation">)</span>\n<span class="token punctuation">}</span><span class="token punctuation">)</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><h4 id="_2-5-3-真正的主角-eval-和-eval" tabindex="-1"><a class="header-anchor" href="#_2-5-3-真正的主角-eval-和-eval" aria-hidden="true">#</a> 2.5.3 真正的主角 <code>$eval</code> 和 <code>?eval</code></h4><p>上面的两个api一起用就变成了eval，我最常用的api之一。一个api顶上面两个，集中一起写，舒服。</p><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code><span class="token keyword">const</span> result <span class="token operator">=</span> <span class="token keyword">await</span> page<span class="token punctuation">.</span><span class="token function">$eval</span><span class="token punctuation">(</span>selector<span class="token punctuation">,</span> <span class="token parameter">el</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span>\n    <span class="token comment">//如果需要赋值要返回Promise</span>\n    <span class="token keyword">return</span> <span class="token keyword">new</span> <span class="token class-name">Promise</span><span class="token punctuation">(</span><span class="token parameter">resolve</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span>\n        <span class="token comment">//...一波骚操作</span>\n        <span class="token comment">//可以用Dom api啦</span>\n        <span class="token function">reslove</span><span class="token punctuation">(</span>obj<span class="token punctuation">)</span>\n    <span class="token punctuation">}</span><span class="token punctuation">)</span>\n<span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\n<span class="token keyword">await</span> iframe<span class="token punctuation">.</span><span class="token function">$$eval</span><span class="token punctuation">(</span>selector<span class="token punctuation">,</span> <span class="token parameter">el</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span><span class="token operator">...</span><span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><h3 id="_2-6-监听事件" tabindex="-1"><a class="header-anchor" href="#_2-6-监听事件" aria-hidden="true">#</a> 2.6 监听事件</h3><p>上文说过在<code>page.evaluate</code>中用<code>console</code>是不能在node命令行打印出来的，不过有了监听事件就可以改变这个规则了。也可以在监听事件里面做容错处理。</p><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code>page<span class="token punctuation">.</span><span class="token function">on</span><span class="token punctuation">(</span><span class="token string">&#39;console&#39;</span><span class="token punctuation">,</span> <span class="token parameter">msg</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span>\n    console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>msg<span class="token punctuation">)</span><span class="token punctuation">;</span>\n<span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>个人觉得如果打印dom的话，还是看浏览器的console比较好，直观。</p><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code><span class="token comment">//监听浏览器报错</span>\npage<span class="token punctuation">.</span><span class="token function">on</span><span class="token punctuation">(</span><span class="token string">&#39;pageerror&#39;</span><span class="token punctuation">,</span> <span class="token parameter">pageErr</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span>\n    console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>pageErr<span class="token punctuation">)</span><span class="token punctuation">;</span>\n<span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\n<span class="token comment">//监听node报错</span>\npage<span class="token punctuation">.</span><span class="token function">on</span><span class="token punctuation">(</span><span class="token string">&#39;error&#39;</span><span class="token punctuation">,</span> <span class="token parameter">err</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span>\n    console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>err<span class="token punctuation">)</span><span class="token punctuation">;</span>\n<span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><h2 id="三、伪装移动端" tabindex="-1"><a class="header-anchor" href="#三、伪装移动端" aria-hidden="true">#</a> 三、伪装移动端</h2><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code><span class="token keyword">const</span> devices <span class="token operator">=</span> <span class="token function">require</span><span class="token punctuation">(</span><span class="token string">&quot;puppeteer/DeviceDescriptors&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\n<span class="token keyword">const</span> iPhone <span class="token operator">=</span> devices<span class="token punctuation">[</span><span class="token string">&quot;iPhone 6&quot;</span><span class="token punctuation">]</span><span class="token punctuation">;</span>\n<span class="token keyword">await</span> page<span class="token punctuation">.</span><span class="token function">emulate</span><span class="token punctuation">(</span>iPhone<span class="token punctuation">)</span><span class="token punctuation">;</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div>',36),r={},u=(0,a(3744).Z)(r,[["render",function(n,s){const a=(0,e.up)("OutboundLink");return(0,e.wg)(),(0,e.iD)(e.HY,null,[p,(0,e._)("p",null,[(0,e._)("a",t,[o,(0,e.Wm)(a)]),c]),l],64)}]])},3744:(n,s)=>{s.Z=(n,s)=>{const a=n.__vccOpts||n;for(const[n,e]of s)a[n]=e;return a}}}]);